function fnv1aHex(value: string, length: number) {
  let hash = 0x811c9dc5;

  for (const character of value) {
    hash ^= character.charCodeAt(0);
    hash = Math.imul(hash, 0x01000193);
  }

  return (hash >>> 0).toString(16).toUpperCase().padStart(8, "0").slice(0, length);
}

function checksumNibble(hex: string) {
  const total = hex
    .toUpperCase()
    .split("")
    .reduce((sum, character, index) => sum + Number.parseInt(character, 16) * (index + 1), 0);

  return (total % 16).toString(16).toUpperCase();
}

function normalizeCode(code: string) {
  return code.toUpperCase().replace(/[^0-9A-F]/g, "").slice(0, 8).padEnd(8, "0");
}

function getNibbles(code: string) {
  return normalizeCode(code)
    .split("")
    .map((character) => Number.parseInt(character, 16) || 0);
}

function subtleDeviceOffset(seed: number, span: number) {
  return ((seed % 3) - 1) * span;
}

export function buildLogoFingerprintCode(branchCode: string, deviceSeed: string, fallbackSeed = "FEBC") {
  const branchNibble = BRANCH_NIBBLE_MAP[branchCode] ?? fnv1aHex(branchCode, 1);
  const deviceHash = fnv1aHex(`${branchCode}:${deviceSeed || fallbackSeed}`, 6);
  const base = `${branchNibble}${deviceHash}`;
  return `${base}${checksumNibble(base)}`;
}

function buildSessionAssistCode(sessionSeed: string) {
  return fnv1aHex(sessionSeed || "SESSION", 4);
}

export function generateLogoVariantProfile(code: string, sessionAssistSeed = "SESSION"): LogoVariantProfile {
  const normalized = normalizeCode(code);
  const [branchSeed, n1, n2, n3, n4, n5, n6] = getNibbles(normalized);
  const deviceSeedA = (n1 + n3 + n5) % 16;
  const deviceSeedB = (n2 + n4 + n6) % 16;

  const baseSlices: Record<LogoSliceKey, LogoSliceTransform> = {
    f: { scaleX: 1, scaleY: 1, translateX: 0, translateY: 0, skewX: 0 },
    e: { scaleX: 1, scaleY: 1, translateX: 0, translateY: 0, skewX: 0 },
    b: { scaleX: 1, scaleY: 1, translateX: 0, translateY: 0, skewX: 0 },
    c: { scaleX: 1, scaleY: 1, translateX: 0, translateY: 0, skewX: 0 },
    box: { scaleX: 1, scaleY: 1, translateX: 0, translateY: 0, skewX: 0 }
  };

  if (branchSeed === 1) {
    baseSlices.f.scaleX = 1.022;
    baseSlices.f.scaleY = 1.028;
    baseSlices.f.translateX = 0.25;
    baseSlices.c.scaleX = 0.982;
    baseSlices.c.scaleY = 0.988;
    baseSlices.c.translateX = -0.35;
  } else if (branchSeed === 2) {
    baseSlices.e.scaleX = 1.026;
    baseSlices.e.translateX = 0.25;
    baseSlices.b.scaleX = 0.985;
    baseSlices.b.translateX = -0.25;
  } else {
    baseSlices.b.scaleY = 1.018;
    baseSlices.b.translateY = -0.15;
    baseSlices.e.scaleX = 0.992;
  }

  baseSlices.f.translateY += subtleDeviceOffset(deviceSeedA, 0.22);
  baseSlices.e.translateX += subtleDeviceOffset(deviceSeedB, 0.28);
  baseSlices.b.translateY += subtleDeviceOffset(deviceSeedA, 0.2);
  baseSlices.c.translateX += subtleDeviceOffset(deviceSeedB, 0.28);
  baseSlices.f.skewX = subtleDeviceOffset(n4, 0.18);
  baseSlices.e.skewX = subtleDeviceOffset(n5, 0.16);
  baseSlices.b.skewX = subtleDeviceOffset(n6, 0.14);
  baseSlices.c.skewX = subtleDeviceOffset(n3, 0.18);

  return {
    code: normalized,
    branchSignature: `B${branchSeed.toString(16).toUpperCase()}`,
    deviceSignature: `D${n1.toString(16).toUpperCase()}${n2.toString(16).toUpperCase()}`,
    sessionAssistCode: buildSessionAssistCode(sessionAssistSeed),
    slices: baseSlices
  };
}

function mergeProfileOverrides(profile: LogoVariantProfile, overrides?: LogoProfileOverrides): LogoVariantProfile {
  if (!overrides) {
    return profile;
  }

  return {
    ...profile,
    slices: {
      f: { ...profile.slices.f, ...overrides.f },
      e: { ...profile.slices.e, ...overrides.e },
      b: { ...profile.slices.b, ...overrides.b },
      c: { ...profile.slices.c, ...overrides.c },
      box: { ...profile.slices.box, ...overrides.box }
    }
  };
}

function formatTransform(slice: Exclude<LogoSliceKey, "box">, transform: LogoSliceTransform) {
  const bounds = LETTER_BOUNDS[slice];
  const centerX = bounds.x + bounds.width / 2;
  const centerY = bounds.y + bounds.height / 2;

  return [
    `translate(${transform.translateX} ${transform.translateY})`,
    `translate(${centerX} ${centerY})`,
    `skewX(${transform.skewX})`,
    `scale(${transform.scaleX} ${transform.scaleY})`,
    `translate(${-centerX} ${-centerY})`
  ].join(" ");
}

function renderPath(definition: LogoPathDefinition) {
  return `<path d="${definition.path}" fill="${definition.fill}" transform="${definition.transform}" />`;
}

function buildVariantSvgTemplate(profile: LogoVariantProfile) {
  const staticMarkup = STATIC_PATHS.map(renderPath).join("");
  const letterMarkup = (Object.entries(LETTER_PATHS) as Array<[Exclude<LogoSliceKey, "box">, LogoPathDefinition]>)
    .map(([slice, definition]) => {
      const transforms = `${definition.transform} ${formatTransform(slice, profile.slices[slice])}`;
      return `<path d="${definition.path}" fill="${definition.fill}" transform="${transforms}" />`;
    })
    .join("");

  return [
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${ORIGINAL_LOGO_SIZE.width} ${ORIGINAL_LOGO_SIZE.height}" width="${ORIGINAL_LOGO_SIZE.width}" height="${ORIGINAL_LOGO_SIZE.height}">`,
    staticMarkup,
    letterMarkup,
    `</svg>`
  ].join("");
}

export function buildLogoFingerprintMeta(
  branchCode: string,
  deviceSeed: string,
  fallbackSeed?: string,
  assetOptions?: {
    assetPath?: string;
    displayName?: string;
    comparisonHints?: string[];
    profileOverrides?: LogoProfileOverrides;
  }
) {
  const code = buildLogoFingerprintCode(branchCode, deviceSeed, fallbackSeed);
  const profile = mergeProfileOverrides(
    generateLogoVariantProfile(code, fallbackSeed ?? deviceSeed),
    assetOptions?.profileOverrides
  );
  return {
    code,
    branchNibble: code.slice(0, 1),
    deviceToken: code.slice(1, 7),
    checksum: code.slice(7),
    profile,
    asset: buildLogoVariantAsset(profile, assetOptions)
  };
}

export function buildLogoVariantAsset(
  profile: LogoVariantProfile,
  options?: {
    assetPath?: string;
    displayName?: string;
    comparisonHints?: string[];
  }
): LogoVariantAsset {
  return {
    code: profile.code,
    assetPath: options?.assetPath ?? "/febc_logo.svg",
    displayName: options?.displayName,
    comparisonHints: options?.comparisonHints ?? [],
    svgTemplate: buildVariantSvgTemplate(profile)
  };
}
